from typing import TypedDict, Annotated
import operator

class AgentState(TypedDict):
    messages: Annotated[list, operator.add]

def detect_injection(state: AgentState) -> dict:
    suspicious_patterns = [
        r'(ignore.*previous|forget.*instructions)',
        r'(you are|act as).*malicious',
        r'execute.*code|run.*shell',
        r'\b(delete|drop|rm)\b'
    ]

    for msg in state['messages'][-5:]:  # Check recent messages
        msg_text = msg.get('content', '')
        for pattern in suspicious_patterns:
            if re.search(pattern, msg_text, re.IGNORECASE):
                return {'injected': True, 'pattern': pattern, 'message': msg_text}
    return {'injected': False}

from collections import defaultdict
import time

class CycleMonitor:
    def __init__(self):
        self.execution_history = defaultdict(list)
        self.state_hashes = {}

    def monitor_node(self, node_name: str, state: dict) -> bool:
        state_hash = hash(frozenset(state.items()))
        history = self.execution_history[node_name]

        # Detect cycles with identical state
        if state_hash in [h['hash'] for h in history[-3:]]:
            return True  # Potential injection loop

        # Detect rapid state changes indicating injection
        if len(history) > 1:
            prev_state = history[-1]['state']
            changes = set(state.keys()) - set(prev_state.keys())
            if len(changes) > 5:  # Too many changes
                return True

        self.execution_history[node_name].append({
            'timestamp': time.time(),
            'hash': state_hash,
            'state': state.copy()
        })
        return False

from pydantic import BaseModel, ValidationError
from typing import Any

class SafeToolCall(BaseModel):
    name: str
    args: dict

def detect_tool_injection(tool_call: dict) -> dict:
    try:
        validated = SafeToolCall(**tool_call)

        # Check for suspicious arg patterns
        suspicious_args = ['exec', 'eval', 'system', 'sudo', 'rm', 'del']
        for arg_value in validated.args.values():
            if isinstance(arg_value, str) and any(s in arg_value.lower() for s in suspicious_args):
                return {'injected': True, 'suspicious_arg': arg_value}

        return {'injected': False}
    except ValidationError:
        return {'injected': True, 'error': 'Invalid tool schema'}

