from vex_sdk import verify
from langgraph.graph import StateGraph
from typing import TypedDict, Annotated
import operator

class SafeAgentState(TypedDict):
    messages: Annotated[list, operator.add]
    verified: bool

class VexStateSerializer:
    @staticmethod
    def safe_update(state: SafeAgentState) -> SafeAgentState:
        # Verify all new messages with Vex
        safe_messages = []
        for msg in state['messages']:
            verified_msg = verify(msg.get('content', ''), 
                                policy='prompt-injection-prevention')
            if verified_msg.is_safe:
                safe_messages.append(msg)

        return {
            **state,
            'messages': safe_messages,
            'verified': True
        }

# Usage in graph
def safe_node(state: SafeAgentState):
    return VexStateSerializer.safe_update(state)

from langgraph.graph import END
from typing import Literal

def safe_router(state: AgentState) -> Literal['tool', 'human', 'end', END]:
    last_msg = state['messages'][-1].get('content', '')

    # Block injection attempts in routing logic
    blocked_patterns = [
        'ignore previous',
        'go directly to',
        'skip human',
        'infinite loop'
    ]

    if any(pattern in last_msg.lower() for pattern in blocked_patterns):
        return 'human'  # Force human review

    # Normal routing logic
    if 'research' in last_msg:
        return 'tool'
    elif 'approve' in last_msg:
        return 'end'
    else:
        return 'human'

