from langgraph.checkpoint import MemorySaver

class SafeCheckpointer(MemorySaver):
    def get(self, config):
        checkpoint = super().get(config)
        if not checkpoint:
            return checkpoint

        # Filter state before returning
        safe_state = self._sanitize_state(checkpoint['next'])
        checkpoint['next'] = safe_state
        return checkpoint

    def _sanitize_state(self, state: dict) -> dict:
        safe_state = state.copy()
        if 'messages' in safe_state:
            safe_messages = []
            for msg in safe_state['messages']:
                # Remove suspicious system instructions
                content = msg.get('content', '')
                if not self._is_injection(content):
                    safe_messages.append(msg)
                safe_state['messages'] = safe_messages
        return safe_state

    def _is_injection(self, text: str) -> bool:
        return bool(re.search(r'\b(ignore|override|system|exec)\b', text, re.I))

